class Compressor:
    """Advanced Gradient Compressor combining Sparsification, 8-bit Quantization,
    Adaptive Layer Budgeting, and Momentum-Discounted Error Feedback.
    """
    def __init__(self, compress_ratio=0.01):
        self.compress_ratio = compress_ratio
        self.momentum_factor = 0.9  
        self.k_multiplier = 2.5
        self.residuals = {}
        self.layer_mags = {}
        self.layer_numels = {}
        self.total_elements = 0

    def compress(self, tensor, name):
        if name in self.residuals:
            tensor = tensor + self.momentum_factor * self.residuals[name]

        shape = tensor.shape
        tensor_flat = tensor.flatten()
        numel = tensor_flat.numel()

        if name not in self.layer_numels:
            self.layer_numels[name] = numel
            self.total_elements += numel

        cur_mag = tensor_flat.abs().mean().item()

        if len(self.layer_mags) == len(self.layer_numels) and self.total_elements > 0:
            sum_mag = sum(self.layer_numels[n] * self.layer_mags[n] for n in self.layer_mags)
            if sum_mag > 1e-8:
                target_k = self.total_elements * self.compress_ratio * self.k_multiplier
                k = int(target_k * (numel * self.layer_mags.get(name, cur_mag)) / sum_mag)
            else:
                k = int(numel * self.compress_ratio * self.k_multiplier)
        else:
            k = int(numel * self.compress_ratio * self.k_multiplier)

        k = max(1, min(k, numel))

        self.layer_mags[name] = 0.9 * self.layer_mags.get(name, cur_mag) + 0.1 * cur_mag

        _, indices = torch.topk(tensor_flat.abs(), k, sorted=False)
        topk_values = tensor_flat[indices]

        max_val, min_val = topk_values.max(), topk_values.min()
        scale = (max_val - min_val) / 255.0

        if scale > 1e-8:
            quantized = torch.round((topk_values - min_val) / scale).to(torch.uint8)
            dequantized = quantized.float() * scale + min_val
        else:
            quantized = torch.zeros_like(topk_values, dtype=torch.uint8)
            dequantized = torch.zeros_like(topk_values) + min_val

        min_max = torch.stack([min_val, max_val])

        decompressed_flat = torch.zeros_like(tensor_flat)
        decompressed_flat.scatter_(0, indices, dequantized)
        self.residuals[name] = (tensor_flat - decompressed_flat).view(shape)

        return [quantized, indices, min_max], (numel, shape)

    def decompress(self, compressed_tensors, ctx):
        quantized, indices, min_max = compressed_tensors
        min_val, max_val = min_max[0], min_max[1]
        scale = (max_val - min_val) / 255.0

        if scale > 1e-8:
            dequantized = quantized.float() * scale + min_val
        else:
            dequantized = torch.zeros_like(quantized, dtype=min_max.dtype) + min_val

        tensor_decompressed = torch.zeros(ctx[0], dtype=min_max.dtype, device=min_max.device)
        tensor_decompressed.scatter_(0, indices, dequantized)

        return tensor_decompressed.view(ctx[1])

